class Solution {
public:
void push(int x) {
  elements.push_back(x);
}
int pop() {
  if (elements.empty()) throw std::runtime_error("Stack is empty");
  int top_element = elements.back();
  elements.pop_back();
  return top_element;
}
int count() {
  return elements.size();
}
private:
std::vector<int> elements;
};

int main() {
  Solution s;
  int input_array[] = {1, 2, 3, 4, 5};
  int n = sizeof(input_array) / sizeof(input_array[0]);
  for (int i = 0; i < n; i++)
    s.push(input_array[i]);
  std::cout << s.count() << std::endl;
  return 0;
}
